// Build Veeqo URL with optional incremental cursor
const cursorData = $('Read Sync Cursor').all();
const cursorValue = cursorData.length > 0 && cursorData[0].json.cursor_value
  ? cursorData[0].json.cursor_value : null;

// Veeqo max page_size is 250
let url = 'https://api.veeqo.com/products?page_size=250';
if (cursorValue) {
  url += '&updated_at_min=' + encodeURIComponent(cursorValue);
}

return [{ json: { veeqoUrl: url, isIncremental: !!cursorValue, cursor: cursorValue } }];

// Transform Veeqo products into Supabase upsert payload
const veeqoProducts = $('Fetch Veeqo Products').all();
const existingProducts = $('Fetch Existing Products').all();
const warehouseItems = $('Fetch Warehouses').all();

// Build lookup: veeqo_id -> existing Supabase UUID
const existingMap = {};
for (const ep of existingProducts) {
  const vid = ep.json.external_ids?.veeqo;
  if (vid) existingMap[vid] = ep.json.id;
}

// Build warehouse map: external_id -> UUID
const warehouseMap = {};
for (const w of warehouseItems) {
  if (w.json.external_id) warehouseMap[w.json.external_id] = w.json.id;
}

const products = [];
for (const item of veeqoProducts) {
  const vp = item.json;
  if (!vp.id) continue;
  const veeqoId = String(vp.id);
  const existingId = existingMap[veeqoId];
  const hasKit = (vp.sellables || []).some(s => s.type === 'Kit');
  products.push({
    ...(existingId ? { id: existingId } : {}),
    title: vp.title || '(untitled)',
    description: vp.description || null,
    brand: vp.brand || null,
    product_type: hasKit ? 'kit' : 'standard',
    origin_country: vp.origin_country || 'US',
    hs_tariff_code: vp.hs_tariff_number || null,
    main_image_url: vp.main_image_src || null,
    external_ids: { veeqo: veeqoId }
  });
}

return [{ json: { payload: products, warehouseMap, count: products.length } }];

// Build variants payload using product UUIDs from upsert response
const upsertedProducts = $('Upsert Products').all();
const veeqoProducts = $('Fetch Veeqo Products').all();

// Map veeqo product ID -> Supabase UUID
const productIdMap = {};
for (const item of upsertedProducts) {
  const vid = item.json.external_ids?.veeqo;
  if (vid) productIdMap[vid] = item.json.id;
}

const variants = [];
for (const item of veeqoProducts) {
  const vp = item.json;
  if (!vp.id) continue;
  const productId = productIdMap[String(vp.id)];
  if (!productId) continue;

  for (const vs of (vp.sellables || [])) {
    if (!vs.sku_code) continue;
    const weightOz = vs.weight_grams ? +(vs.weight_grams / 28.3495).toFixed(2) : 0;
    const dims = vs.measurement_attributes || {};
    variants.push({
      product_id: productId,
      sku: vs.sku_code,
      title: vs.sellable_title || null,
      upc: vs.upc_code || null,
      price: +(vs.price || 0),
      cost_price: +(vs.cost_price || 0),
      weight_oz: weightOz,
      length_in: dims.depth || null,
      width_in: dims.width || null,
      height_in: dims.height || null,
      customs_description: vs.customs_description || null,
      is_active: vs.deleted_at == null,
      external_ids: { veeqo: String(vs.id) }
    });
  }
}

return [{ json: { payload: variants, count: variants.length } }];

// Build kit component and inventory payloads using variant UUIDs
const upsertedVariants = $('Upsert Variants').all();
const veeqoProducts = $('Fetch Veeqo Products').all();
const warehouseMap = $('Transform Products').first().json.warehouseMap || {};

// SKU -> Supabase variant UUID
const skuToId = {};
for (const item of upsertedVariants) {
  if (item.json.sku) skuToId[item.json.sku] = item.json.id;
}

const kits = [];
const inventory = [];

for (const item of veeqoProducts) {
  const vp = item.json;
  for (const vs of (vp.sellables || [])) {
    if (!vs.sku_code) continue;
    const variantId = skuToId[vs.sku_code];
    if (!variantId) continue;

    // Kit components
    if (vs.type === 'Kit' && vs.contents) {
      for (const comp of vs.contents) {
        if (!comp.sku_code) continue;
        const compId = skuToId[comp.sku_code];
        if (!compId) continue;
        kits.push({
          kit_variant_id: variantId,
          component_variant_id: compId,
          quantity: comp.quantity || 1
        });
      }
    }

    // Inventory levels
    for (const se of (vs.stock_entries || [])) {
      const whId = warehouseMap[String(se.warehouse_id)];
      if (!whId) continue;
      inventory.push({
        variant_id: variantId,
        warehouse_id: whId,
        physical_qty: se.physical_stock_level || 0,
        allocated_qty: se.allocated_stock_level || 0,
        incoming_qty: se.incoming_stock_level || 0
      });
    }
  }
}

return [{ json: { kitPayload: kits, inventoryPayload: inventory, kitCount: kits.length, inventoryCount: inventory.length } }];
